const updateEndpoint = `-- name: UpdateEndpoint :execresult
UPDATE convoy.endpoints SET
    name = $1, status = $2, owner_id = $3,
    url = $4, description = $5, http_timeout = $6,
    rate_limit = $7, rate_limit_duration = $8,
    advanced_signatures = $9,
    slack_webhook_url = $10, support_email = $11,
    authentication_type = $12,
    authentication_type_api_key_header_name = $13,
    authentication_type_api_key_header_value_cipher = CASE
        WHEN is_encrypted THEN pgp_sym_encrypt($14, $15)
    END,
    authentication_type_api_key_header_value = CASE
        WHEN is_encrypted THEN ''
        ELSE $14
    END,
    secrets_cipher = CASE
        WHEN is_encrypted THEN pgp_sym_encrypt($16::TEXT, $15)
    END,
    secrets = CASE
        WHEN is_encrypted THEN '[]'
        ELSE $16::jsonb
    END,
    mtls_client_cert = CASE
        WHEN is_encrypted THEN NULL
        ELSE $17::jsonb
    END,
    mtls_client_cert_cipher = CASE
        WHEN is_encrypted THEN pgp_sym_encrypt($17::TEXT, $15)
    END,
    oauth2_config = CASE
        WHEN is_encrypted THEN NULL
        ELSE $18::jsonb
    END,
    oauth2_config_cipher = CASE
        WHEN is_encrypted THEN pgp_sym_encrypt($18::TEXT, $15)
    END,
    basic_auth_config = CASE
        WHEN is_encrypted THEN NULL
        ELSE $19::jsonb
    END,
    basic_auth_config_cipher = CASE
        WHEN is_encrypted THEN pgp_sym_encrypt($19::TEXT, $15)
    END,
    updated_at = NOW(), content_type = $20
WHERE id = $21 AND project_id = $22 AND deleted_at IS NULL
`

